import com.fasterxml.jackson.databind.type.TypeFactory;
import com.fasterxml.jackson.databind.type.CollectionType;
import com.fasterxml.jackson.databind.JavaType;

public class TestOtherCollections {
    public static void main(String[] args) {
        TypeFactory factory = TypeFactory.defaultInstance();

        String[] testTypes = {"java.util.List", "java.util.Set", "java.util.Collection", "java.util.Queue"};

        for (String typeName : testTypes) {
            System.out.println("Testing: " + typeName);
            try {
                JavaType type = factory.constructFromCanonical(typeName);
                System.out.println("  Raw class: " + type.getRawClass().getName());
                System.out.println("  Is CollectionType: " + (type instanceof CollectionType));

                if (type instanceof CollectionType) {
                    CollectionType collectionType = (CollectionType) type;
                    System.out.println("  Content type: " + collectionType.getContentType().getRawClass().getName());
                    System.out.println("  Success!");
                } else {
                    System.out.println("  ERROR: Not a CollectionType!");
                }
            } catch (Exception e) {
                System.out.println("  Exception: " + e.getMessage());
                e.printStackTrace();
            }
            System.out.println();
        }
    }
}

